package automation

import (
	"context"

	"google.golang.org/grpc"

	"github.snooguts.net/reddit/devplatform-api/go/grpc/devvit/reddit/v2alpha"
	"github.snooguts.net/reddit/reddit-devplatform-monorepo/go-common/generated/protos/types/devvit/actor/automation"
	"github.snooguts.net/reddit/reddit-devplatform-monorepo/go-common/grpc/proxyutil"
)

type OnModActionProxy struct {
	automation.UnimplementedOnModActionServer
	client automation.OnModActionClient
}

func init() {
	proxyutil.Register(&automation.OnModAction_ServiceDesc, NewOnModActionProxy)
}
func NewOnModActionProxy(cc grpc.ClientConnInterface) automation.OnModActionServer {
	return &OnModActionProxy{client: automation.NewOnModActionClient(cc)}
}
func (p *OnModActionProxy) OnModAction(ctx context.Context, in *v2alpha.ModAction) (*automation.HandlerResult, error) {
	return proxyutil.ProxyMethod[v2alpha.ModAction, automation.HandlerResult](p.client.OnModAction)(ctx, in)
}
